+// ─── Character-Furniture Interaction System ─────────────────────────
+
+type FurnitureType = 'desk' | 'forge' | 'lectern' | 'chair' | 'workbench' | 'none';
+
+interface InteractionPose {
+  spriteModifications: string[]; // lines of sprite modifications to overlay or replace
+  offsetX: number;
+  offsetY: number;
+}
+
+/**
+ * Returns the interaction pose modifications for a character near furniture.
+ * This modifies the base sprite to show sitting, standing at forge, or reading poses.
+ * @param type CharacterType
+ * @param furniture FurnitureType
+ * @returns InteractionPose or null if no interaction pose
+ */
+export function getInteractionPose(type: CharacterType, furniture: FurnitureType): InteractionPose | null {
+  // Define simple sprite modifications for interaction poses
+  // These modifications overlay or replace certain lines to simulate sitting/working poses.
+  // For simplicity, we define only for knight (sitting at desk), blacksmith (standing at forge), scribe (reading at lectern).
+
+  if (furniture === 'chair' || furniture === 'desk' || furniture === 'workbench') {
+    // Sitting pose: lower legs tucked, arms on desk/workbench
+    switch (type) {
+      case 'knight':
+      case 'squire':
+      case 'nobility':
+      case 'scribe':
+      case 'judge':
+      case 'king':
+        return {
+          spriteModifications: [
+            '       OAAAAAO       ', // head unchanged
+            '      OAAAAAAAO      ',
+            '     OMMMMMMMMO      ',
+            '     OMMMMMMMMO      ',
+            '    OMMMMMMMMMMO     ',
+            '    OMMEEMMEEMMO     ',
+            '    OMMEEMMEEMMO     ',
+            '   OMMCCCCCCCCMMO    ',
+            '   OMMCCGGGGCCMMO    ',
+            '   OMMCCCCCCCCMMO    ',
+            '   OMMMMMMMMMMMMO    ',
+            '   OMMMMMMMMMMMMO    ',
+            '    OMMMMMMMMMMO     ',
+            '    OMMMMMMMMMMO     ',
+            '    OMMMMMMMMMMO     ',
+            '    OMMMMMMMMMMO     ',
+            '    OMMMMMMMMMMO     ',
+            '    OMMMMMMMMMMO     ',
+            '    OMMMMMMMMMMO     ',
+            '    O    MMMM  O     ', // legs tucked in sitting pose
+            '    O    MMMM  O     ',
+            '    O    MMMM  O     ',
+            '    O    MMMM  O     ',
+            '     OMMMMMMMO      ',
+          ],
+          offsetX: 0,
+          offsetY: 4,
+        };
+      default:
+        return null;
+    }
+  } else if (furniture === 'forge') {
+    // Standing at forge pose: arms forward, slight lean
+    if (type === 'blacksmith') {
+      return {
+        spriteModifications: [
+          '       OHHHHHO       ',
+          '      OHHHHHHHO      ',
+          '     OHSSSSSHO       ',
+          '     OSESSEESSO      ',
+          '    OSsSsSsSsSO      ',
+          '    OSSSSSSSSSO      ',
+          '   OPPPPPPPPP0       ',
+          '  OPPPPPPPPPPO       ',
+          '  OPPPMMPPPPPO       ',
+          '  OPPMMMMPPPO        ',
+          '  OPPPPPPPPP0        ',
+          '   OPPpApPPP0        ',
+          '    OPPPPPPP0        ',
+          '    OPPPPPPP0        ',
+          '    OPPpPPPP0        ',
+          '    OPPOPPPO         ',
+          '    OPPPOPP0         ',
+          '    OBBBOBBBO        ',
+          '    OBBBOBBBO        ',
+          '                    ',
+          '                    ',
+          '                    ',
+          '                    ',
+        ],
+        offsetX: 0,
+        offsetY: 0,
+      };
+    }
+    return null;
+  } else if (furniture === 'lectern') {
+    // Reading pose: head tilted down, hands on book
+    if (type === 'scribe' || type === 'judge' || type === 'nobility') {
+      return {
+        spriteModifications: [
+          '       OHHHHHO       ',
+          '      OHHHHHHHO      ',
+          '     OSSSSSSSSSO     ',
+          '     OSESSEESSO      ',
+          '    OSsSsSsSsSO      ',
+          '    OSSSSSSSSSO      ',
+          '   OPPPPPPPPP0       ',
+          '   OPPPPPPPPP0       ',
+          '   OPPTTTTPPP0       ',
+          '   OPPTTTTPPP0       ',
+          '   OPPPPPPPPP0       ',
+          '   OPPpppPPP0        ',
+          '    OPPPPPPP0        ',
+          '    OPPPPPPP0        ',
+          '    OPPpPPPP0        ',
+          '    OPPOPPPO         ',
+          '    OPPPOPP0         ',
+          '    OBBBOBBBO        ',
+          '    OBBBOBBBO        ',
+          '                    ',
+          '                    ',
+          '                    ',
+          '                    ',
+        ],
+        offsetX: 0,
+        offsetY: 0,
+      };
+    }
+    return null;
+  }
+  return null;
+}
+
+/**
+ * Draw visual indicator around character when near furniture.
+ * @param ctx CanvasRenderingContext2D
+ * @param x Character x position
+ * @param y Character y position
+ * @param s Scale
+ */
+export function drawInteractionIndicator(ctx: CanvasRenderingContext2D, x: number, y: number, s: number) {
+  ctx.save();
+  ctx.strokeStyle = 'rgba(255, 215, 0, 0.8)';
+  ctx.lineWidth = 2;
+  ctx.beginPath();
+  ctx.ellipse(x + 8 * s, y + 24 * s, 10 * s, 4 * s, 0, 0, Math.PI * 2);
+  ctx.stroke();
+  ctx.restore();
+}
+
+/**
+ * Determine if character is near furniture in room and return furniture type.
+ * This is a stub function; in real usage, would depend on character position and room layout.
+ * @param type CharacterType
+ * @param x Character x position
+ * @param y Character y position
+ * @param roomX Room x
+ * @param roomY Room y
+ * @param roomW Room width
+ * @param roomH Room height
+ * @returns FurnitureType or 'none'
+ */
+export function getNearbyFurniture(type: CharacterType, x: number, y: number, roomX: number, roomY: number, roomW: number, roomH: number): FurnitureType {
+  // Simple heuristic based on room type and character position
+  switch (type) {
+    case 'scribe':
+    case 'judge':
+    case 'nobility':
+    case 'king':
+    case 'squire':
+    case 'knight':
+      // Check if near desk or chair area (e.g., lower center of room)
+      if (x > roomX + roomW * 0.3 && x < roomX + roomW * 0.7 && y > roomY + roomH * 0.5) {
+        return 'chair';
+      }
+      break;
+    case 'blacksmith':
+      // Near forge area (left side)
+      if (x < roomX + roomW * 0.4 && y > roomY + roomH * 0.2 && y < roomY + roomH * 0.6) {
+        return 'forge';
+      }
+      break;
+    case 'scribe':
+      // Near lectern area (right side)
+      if (x > roomX + roomW * 0.6 && y > roomY + roomH * 0.4 && y < roomY + roomH * 0.7) {
+        return 'lectern';
+      }
+      break;
+  }
+  return 'none';
+}
+
+/**
+ * Draw character with interaction pose if near furniture, with smooth transition.
+ * @param ctx CanvasRenderingContext2D
+ * @param type CharacterType
+ * @param state AnimState
+ * @param x Character x position
+ * @param y Character y position
+ * @param s Scale
+ * @param frame Animation frame
+ * @param roomX Room x
+ * @param roomY Room y
+ * @param roomW Room width
+ * @param roomH Room height
+ * @param agentId Optional agent id
+ * @param currentJob Optional current job string
+ */
+export function drawCharacterWithInteraction(
+  ctx: CanvasRenderingContext2D,
+  type: CharacterType,
+  state: AnimState,
+  x: number,
+  y: number,
+  s: number,
+  frame: number,
+  roomX: number,
+  roomY: number,
+  roomW: number,
+  roomH: number,
+  agentId?: string,
+  currentJob?: string | null,
+) {
+  const id = agentId ?? `${type}-${Math.round(x)}`;
+  const cs = getCS(id, x, y);
+
+  // Determine nearby furniture
+  const furniture = getNearbyFurniture(type, cs.x, cs.y, roomX, roomY, roomW, roomH);
+  const interactionPose = getInteractionPose(type, furniture);
+
+  // Smooth transition factor for interaction pose (0 to 1)
+  if (!('interactionTransition' in cs)) (cs as any).interactionTransition = 0;
+  const targetTransition = interactionPose ? 1 : 0;
+  (cs as any).interactionTransition = lerp((cs as any).interactionTransition, targetTransition, 0.1);
+
+  // Base sprite selection (walking or idle)
+  let baseSprite: string[];
+  if (cs.moving) {
+    const walkFrames = WALK_FRAMES_MAP[type] || [SPRITE_MAP[type]];
+    const wfIndex = cs.wf % walkFrames.length;
+    baseSprite = walkFrames[wfIndex];
+  } else {
+    const idleFrames = IDLE_FRAMES_MAP[type] || [SPRITE_MAP[type]];
+    const idleIndex = Math.floor(frame / IDLE_FRAME_DURATION) % idleFrames.length;
+    baseSprite = idleFrames[idleIndex];
+  }
+
+  // If interaction pose, blend sprite lines with base sprite lines
+  let finalSprite = baseSprite;
+  if (interactionPose && (cs as any).interactionTransition > 0.01) {
+    const t = (cs as any).interactionTransition;
+    finalSprite = [];
+    for (let i = 0; i < baseSprite.length; i++) {
+      const baseLine = baseSprite[i] || '';
+      const modLine = interactionPose.spriteModifications[i] || '';
+      if (modLine.length === 0) {
+        finalSprite.push(baseLine);
+      } else {
+        // Blend lines character by character
+        let blendedLine = '';
+        for (let c = 0; c < baseLine.length; c++) {
+          const baseChar = baseLine[c] || ' ';
+          const modChar = modLine[c] || ' ';
+          blendedLine += t > 0.5 ? modChar : baseChar;
+        }
+        finalSprite.push(blendedLine);
+      }
+    }
+  }
+
+  // Bobbing offset for animation
+  const bob = state === 'idle' ? Math.sin(frame * 0.05) * 1.2 : state === 'working' ? Math.sin(frame * 0.1) * 0.8 : 0;
+  const drawY = cs.y + bob + (interactionPose ? interactionPose.offsetY * s : 0);
+  const flipH = cs.dir === 'left';
+
+  // Drop shadow
+  ctx.fillStyle = 'rgba(0,0,0,0.3)';
+  ctx.beginPath();
+  ctx.ellipse(cs.x + 8 * s, drawY + finalSprite.length * s + 2, 7 * s, 2 * s, 0, 0, Math.PI * 2);
+  ctx.fill();
+
+  const palette = PALETTE_MAP[type];
+  drawSpriteDef(ctx, finalSprite, palette, cs.x + (interactionPose ? interactionPose.offsetX * s : 0), drawY, s, flipH);
+
+  // Walking leg overlay if not interacting strongly
+  if (cs.moving && (!interactionPose || (cs as any).interactionTransition < 0.5)) {
+    const lp = Math.sin(cs.wf * 0.3) * 2 * s;
+    ctx.fillStyle = palette.B;
+    ctx.fillRect(cs.x + 4 * s, drawY + (finalSprite.length - 3) * s + lp, 3 * s, 2 * s);
+    ctx.fillRect(cs.x + 9 * s, drawY + (finalSprite.length - 3) * s - lp, 3 * s, 2 * s);
+  }
+
+  // Draw interaction indicator if near furniture and transition > 0.5
+  if (interactionPose && (cs as any).interactionTransition > 0.5) {
+    drawInteractionIndicator(ctx, cs.x, drawY + finalSprite.length * s, s);
+  }
+
+  drawStatusEffect(ctx, state, cs.x, drawY, s, frame);
+  if (agentId) {
+    updateBubble(id, state, currentJob ?? null, frame);
+    drawBubble(ctx, id, cs.x + 8 * s, drawY - 4);
+  }
+}
+
